CREATE TABLE `StudentMonthlyFees` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `studentId` int(11) NOT NULL,
  `schoolId` int(11) NOT NULL,
  `month` int(11) NOT NULL,
  `calendarYear` int(11) NOT NULL,
  `totalConfiguredAmount` decimal(10,2) NOT NULL,
  `totalAdjustment` decimal(10,2) NOT NULL DEFAULT 0.00,
  `totalPayableAmount` decimal(10,2) NOT NULL,
  `status` enum('UNPAID','PARTIAL','PAID') NOT NULL DEFAULT 'UNPAID',
  `discountReason` text DEFAULT NULL,
  `generatedAt` datetime NOT NULL,
  `generatedBy` int(11) NOT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `deletedAt` datetime DEFAULT NULL,
  `lastEditedAt` datetime DEFAULT NULL,
  `lastEditedBy` int(11) DEFAULT NULL,
  `sessionId` int(11) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `student_month_year_unique` (`studentId`,`calendarYear`,`month`),
  UNIQUE KEY `student_session_month_year_unique` (`studentId`,`sessionId`,`calendarYear`,`month`),
  KEY `schoolId` (`schoolId`),
  KEY `generatedBy` (`generatedBy`),
  KEY `lastEditedBy` (`lastEditedBy`),
  KEY `sessionId` (`sessionId`),
  CONSTRAINT `StudentMonthlyFees_ibfk_482` FOREIGN KEY (`studentId`) REFERENCES `students` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `StudentMonthlyFees_ibfk_483` FOREIGN KEY (`schoolId`) REFERENCES `School` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `StudentMonthlyFees_ibfk_484` FOREIGN KEY (`generatedBy`) REFERENCES `User` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `StudentMonthlyFees_ibfk_485` FOREIGN KEY (`lastEditedBy`) REFERENCES `User` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `StudentMonthlyFees_ibfk_486` FOREIGN KEY (`sessionId`) REFERENCES `academic_sessions` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1487 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
