DROP TABLE IF EXISTS `Transaction`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `Transaction` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `studentName` varchar(255) NOT NULL,
  `schoolId` int(11) NOT NULL,
  `class` varchar(255) NOT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `modeOfPayment` varchar(255) NOT NULL,
  `productId` int(11) DEFAULT NULL,
  `classId` int(11) NOT NULL,
  `sectionId` int(11) NOT NULL,
  `userId` int(11) NOT NULL,
  `isVerified` tinyint(1) NOT NULL DEFAULT 0,
  `verifiedBy` int(11) DEFAULT NULL,
  `verifiedAt` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `schoolId` (`schoolId`),
  KEY `productId` (`productId`),
  KEY `classId` (`classId`),
  KEY `sectionId` (`sectionId`),
  KEY `userId` (`userId`),
  KEY `verifiedBy` (`verifiedBy`),
  CONSTRAINT `Transaction_ibfk_5378` FOREIGN KEY (`schoolId`) REFERENCES `School` (`id`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `Transaction_ibfk_5379` FOREIGN KEY (`productId`) REFERENCES `Product` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `Transaction_ibfk_5380` FOREIGN KEY (`classId`) REFERENCES `class` (`id`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `Transaction_ibfk_5381` FOREIGN KEY (`sectionId`) REFERENCES `Section` (`id`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `Transaction_ibfk_5382` FOREIGN KEY (`userId`) REFERENCES `User` (`id`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `Transaction_ibfk_5383` FOREIGN KEY (`verifiedBy`) REFERENCES `User` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=375 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

