--
-- Table structure for table `attendances`
--

DROP TABLE IF EXISTS `attendances`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `attendances` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `studentId` int(11) NOT NULL,
  `date` date NOT NULL,
  `status` enum('PRESENT','ABSENT') NOT NULL,
  `markedBy` int(11) NOT NULL,
  `schoolId` int(11) NOT NULL,
  `remarks` text DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `sessionId` int(11) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `attendances_student_date_school_unique` (`studentId`,`date`,`schoolId`),
  KEY `attendances_date_index` (`date`),
  KEY `attendances_student_index` (`studentId`),
  KEY `attendances_school_index` (`schoolId`),
  KEY `attendances_status_index` (`status`),
  KEY `attendances_session_index` (`sessionId`),
  KEY `markedBy` (`markedBy`),
  CONSTRAINT `attendances_ibfk_10` FOREIGN KEY (`studentId`) REFERENCES `students` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `attendances_ibfk_11` FOREIGN KEY (`markedBy`) REFERENCES `User` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `attendances_ibfk_12` FOREIGN KEY (`schoolId`) REFERENCES `School` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `attendances_ibfk_13` FOREIGN KEY (`sessionId`) REFERENCES `academic_sessions` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3161 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

