--
-- Table structure for table `payslips`
--

DROP TABLE IF EXISTS `payslips`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `payslips` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `payslipNumber` varchar(50) NOT NULL,
  `staffId` int(11) NOT NULL,
  `month` int(11) NOT NULL,
  `year` int(11) NOT NULL,
  `monthName` varchar(20) NOT NULL,
  `staffName` varchar(255) NOT NULL,
  `staffEmail` varchar(255) NOT NULL,
  `staffMobile` varchar(15) NOT NULL,
  `staffRole` varchar(255) NOT NULL,
  `staffAadhaar` varchar(12) NOT NULL,
  `staffAccountNumber` varchar(20) DEFAULT NULL,
  `staffIfscCode` varchar(11) DEFAULT NULL,
  `schoolName` varchar(255) NOT NULL,
  `schoolAddress` text DEFAULT NULL,
  `schoolPhone` varchar(15) DEFAULT NULL,
  `schoolEmail` varchar(255) DEFAULT NULL,
  `baseSalary` decimal(10,2) NOT NULL,
  `perDaySalary` decimal(10,2) NOT NULL,
  `workingDays` int(11) NOT NULL,
  `totalDays` int(11) NOT NULL DEFAULT 30,
  `presentDays` decimal(4,1) NOT NULL,
  `effectiveSalaryDays` decimal(4,1) NOT NULL,
  `absentDays` int(11) NOT NULL DEFAULT 0,
  `casualLeave` int(11) NOT NULL DEFAULT 0,
  `halfDays` int(11) NOT NULL DEFAULT 0,
  `grossSalary` decimal(10,2) NOT NULL,
  `deductions` decimal(10,2) NOT NULL DEFAULT 0.00,
  `netSalary` decimal(10,2) NOT NULL,
  `totalPaidAmount` decimal(10,2) NOT NULL DEFAULT 0.00,
  `remainingAmount` decimal(10,2) NOT NULL,
  `paymentStatus` enum('UNPAID','PARTIAL','PAID') NOT NULL DEFAULT 'UNPAID',
  `lastPaymentDate` datetime DEFAULT NULL,
  `generatedBy` int(11) NOT NULL,
  `generatedDate` datetime NOT NULL,
  `schoolId` int(11) NOT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `payslip_unique_staff_month` (`staffId`,`month`,`year`),
  UNIQUE KEY `payslip_number_index` (`payslipNumber`),
  KEY `payslip_school_index` (`schoolId`),
  KEY `payslip_period_index` (`month`,`year`),
  KEY `payslip_staff_index` (`staffId`),
  KEY `generatedBy` (`generatedBy`),
  CONSTRAINT `payslips_ibfk_1635` FOREIGN KEY (`generatedBy`) REFERENCES `User` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `payslips_ibfk_1636` FOREIGN KEY (`schoolId`) REFERENCES `School` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=198 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

