--
-- Table structure for table `staff`
--

DROP TABLE IF EXISTS `staff`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `staff` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `staffType` enum('teaching','non-teaching') NOT NULL,
  `name` varchar(255) NOT NULL,
  `gender` enum('Male','Female','Other') NOT NULL,
  `dateOfBirth` date NOT NULL,
  `socialCategory` varchar(100) DEFAULT NULL,
  `mobileNumber` varchar(15) NOT NULL,
  `email` varchar(255) NOT NULL,
  `aadhaarNumber` varchar(12) NOT NULL,
  `nameAsPerAadhaar` varchar(255) NOT NULL,
  `highestAcademicQualification` varchar(255) DEFAULT NULL,
  `tradeDegree` varchar(255) DEFAULT NULL,
  `highestProfessionalQualification` varchar(255) DEFAULT NULL,
  `mathematicsLevel` varchar(50) DEFAULT NULL,
  `scienceLevel` varchar(50) DEFAULT NULL,
  `englishLevel` varchar(50) DEFAULT NULL,
  `socialScienceLevel` varchar(50) DEFAULT NULL,
  `scheduleVIIILanguageLevel` varchar(50) DEFAULT NULL,
  `typeOfDisability` varchar(255) DEFAULT NULL,
  `natureOfAppointment` varchar(100) DEFAULT NULL,
  `dateOfJoiningService` date NOT NULL,
  `dateOfJoiningPresentSchool` date DEFAULT NULL,
  `salaryPerMonth` decimal(10,2) DEFAULT NULL,
  `upiNumber` varchar(50) DEFAULT NULL,
  `accountNumber` varchar(20) DEFAULT NULL,
  `accountName` varchar(255) DEFAULT NULL,
  `ifscCode` varchar(11) DEFAULT NULL,
  `photoUrl` varchar(255) DEFAULT NULL,
  `active` tinyint(1) NOT NULL DEFAULT 1,
  `schoolId` int(11) NOT NULL,
