DROP TABLE IF EXISTS `student_enrollments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_enrollments` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `studentId` int(11) NOT NULL,
  `sessionId` int(11) NOT NULL,
  `classId` int(11) NOT NULL,
  `sectionId` int(11) NOT NULL,
  `rollNumber` varchar(20) DEFAULT NULL,
  `promotedBy` int(11) DEFAULT NULL,
  `promotedAt` datetime DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `enrollment_student_session_unique` (`studentId`,`sessionId`),
  KEY `enrollment_session_class_section_index` (`sessionId`,`classId`,`sectionId`),
  KEY `classId` (`classId`),
  KEY `sectionId` (`sectionId`),
  KEY `promotedBy` (`promotedBy`),
  CONSTRAINT `student_enrollments_ibfk_1` FOREIGN KEY (`studentId`) REFERENCES `students` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `student_enrollments_ibfk_2` FOREIGN KEY (`sessionId`) REFERENCES `academic_sessions` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `student_enrollments_ibfk_3` FOREIGN KEY (`classId`) REFERENCES `class` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `student_enrollments_ibfk_4` FOREIGN KEY (`sectionId`) REFERENCES `Section` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `student_enrollments_ibfk_5` FOREIGN KEY (`promotedBy`) REFERENCES `User` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=163 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
